import { RAGFlowAvatar } from '@/components/ragflow-avatar';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import { useNavigateWithFromState } from '@/hooks/route-hook';
import { useFetchUserInfo } from '@/hooks/user-setting-hooks';
import { cn } from '@/lib/utils';
import { Routes } from '@/routes';
import { Library, MessageSquareText } from 'lucide-react';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocation } from 'umi';
import { BellButton } from './bell-button';

export function Header() {
  const { t } = useTranslation();
  const { pathname } = useLocation();
  const navigate = useNavigateWithFromState();
  const { navigateToOldProfile } = useNavigatePage();
  const isKnowledgeRoute =
    pathname.startsWith(Routes.Datasets) ||
    pathname.startsWith(Routes.DatasetBase) ||
    pathname.startsWith(`${Routes.ParsedResult}/chunks`);
  const isChatRoute =
    pathname.startsWith(Routes.Chats) || pathname.startsWith(Routes.Chat);
  const showTopNav = isKnowledgeRoute || isChatRoute;

  const {
    data: { avatar, nickname },
  } = useFetchUserInfo();

  const topNavData = useMemo(
    () => [
      {
        path: Routes.Datasets,
        name: t('header.dataset', { defaultValue: '知识库' }),
        icon: Library,
        active: isKnowledgeRoute,
      },
      {
        path: Routes.Chats,
        name: t('header.chat', { defaultValue: '应用' }),
        icon: MessageSquareText,
        active: isChatRoute,
      },
    ],
    [isChatRoute, isKnowledgeRoute, t],
  );

  return (
    <section
      className={cn(
        'sticky top-0 z-20 shrink-0 px-6 py-2.5 flex justify-between items-center',
        showTopNav ? 'border-b border-[#d9e6f5]' : 'bg-[#f6f8fb]',
      )}
      style={
        showTopNav
          ? {
              background:
                'linear-gradient(90deg, #f1f5f9 0%, #eef4fa 50%, #eaf3f9 100%)',
            }
          : undefined
      }
    >
      <div className="flex items-center">
        {showTopNav && (
          <button
            type="button"
            className="mr-8 inline-flex items-center gap-1.5 rounded-md px-2 py-1 text-[#1f2937] hover:bg-[#eaf1ff]"
            onClick={() => navigate(Routes.Datasets)}
          >
            <img
              src="/favicon-vende.png"
              alt="VendeFlow"
              className="size-[18px]"
            />
            <span className="text-sm font-semibold tracking-[0.01em]">
              VendeFlow
            </span>
          </button>
        )}
        {showTopNav && (
          <nav className="flex items-center gap-6">
            {topNavData.map((item) => {
              const Icon = item.icon;
              return (
                <button
                  key={item.path}
                  type="button"
                  onClick={() => navigate(item.path as Routes)}
                  className={cn(
                    'relative inline-flex h-8 items-center gap-1.5 px-0 text-sm font-medium transition-colors',
                    item.active
                      ? 'text-[#315efb]'
                      : 'text-[#475569] hover:text-[#334155]',
                  )}
                >
                  <Icon className="size-4" />
                  {item.name}
                  <span
                    className={cn(
                      'absolute -bottom-1 left-0 h-0.5 w-full rounded-full transition-opacity',
                      item.active ? 'bg-[#315efb] opacity-100' : 'opacity-0',
                    )}
                  />
                </button>
              );
            })}
          </nav>
        )}
      </div>
      <div className="flex-1" />
      <div className="flex items-center gap-3 text-text-badge">
        <BellButton></BellButton>
        <div className="relative">
          <RAGFlowAvatar
            name={nickname}
            avatar={avatar}
            className="size-8 cursor-pointer"
            onClick={navigateToOldProfile}
          ></RAGFlowAvatar>
        </div>
      </div>
    </section>
  );
}
